// CONFIG — Set the workflow ID to check (for manual trigger)
// When triggered via webhook, the workflow JSON comes in the request body

const WORKFLOW_ID_TO_CHECK = ''; // Set this to your workflow ID
const N8N_API_URL = '{{$env.N8N_API_URL}}'; // e.g., https://your-instance.app.n8n.cloud/api/v1
const N8N_API_KEY = '{{$env.N8N_API_KEY}}'; // n8n API key

return [{ json: {
  workflow_id: WORKFLOW_ID_TO_CHECK,
  api_url: N8N_API_URL,
  api_key: N8N_API_KEY,
  source: 'manual'
}}];

// STRUCTURAL COMPLIANCE CHECK — Pre-AI validation
// These are mechanical checks that don't need AI

const workflow = $input.all()[0].json;
const nodes = workflow.nodes || [];
const connections = workflow.connections || {};

const issues = [];
const warnings = [];
const passed = [];

// ── CHECK 1: alwaysOutputData on HTTP nodes ──
const httpNodes = nodes.filter(n => n.type === 'n8n-nodes-base.httpRequest');
const zombieNodes = httpNodes.filter(n => n.alwaysOutputData === true);
if (zombieNodes.length > 0) {
  issues.push(`ZOMBIE BUG: ${zombieNodes.length} HTTP nodes have alwaysOutputData=true: ${zombieNodes.map(n => n.name).join(', ')}`);
} else if (httpNodes.length > 0) {
  passed.push(`✅ All ${httpNodes.length} HTTP nodes have alwaysOutputData=false`);
}

// ── CHECK 2: Error routing ──
const httpWithoutErrorRouting = httpNodes.filter(n => !n.onError || n.onError === 'stopWorkflow');
if (httpWithoutErrorRouting.length > 0) {
  warnings.push(`ERROR ROUTING: ${httpWithoutErrorRouting.length} HTTP nodes may stop workflow on error: ${httpWithoutErrorRouting.map(n => n.name).join(', ')}`);
} else if (httpNodes.length > 0) {
  passed.push(`✅ All HTTP nodes have error routing configured`);
}

// ── CHECK 3: Correlation modules present ──
const hasH37 = nodes.some(n => n.name.includes('H37'));
const hasH38 = nodes.some(n => n.name.includes('H38'));
const hasH39 = nodes.some(n => n.name.includes('H39'));
const hasCorrGate = nodes.some(n => n.name.includes('CORRELATION GATE'));
if (!hasH37 || !hasH38 || !hasH39) {
  issues.push(`CORRELATION MODULES MISSING: H37=${hasH37}, H38=${hasH38}, H39=${hasH39}. Required by METATRON v10.7.`);
} else {
  passed.push('✅ All correlation modules (H37/H38/H39) present');
}
if (!hasCorrGate) {
  issues.push('CORRELATION GATE CHECK node not found. Required before Master Merge.');
} else {
  passed.push('✅ Correlation Gate Check node present');
}

// ── CHECK 4: Kill Switch path ──
const hasKillSwitch = nodes.some(n => n.name.toLowerCase().includes('kill switch') || n.name.includes('KILL'));
if (!hasKillSwitch) {
  issues.push('KILL SWITCH path not found. Required by IRONCLAD v2.0.');
} else {
  passed.push('✅ Kill Switch path present');
}

// ── CHECK 5: Telegram alerting ──
const hasTelegram = nodes.some(n => n.type === 'n8n-nodes-base.telegram');
if (!hasTelegram) {
  warnings.push('No Telegram alert nodes found. Recommended for kill switch and scan complete notifications.');
} else {
  passed.push(`✅ Telegram alerting configured (${nodes.filter(n => n.type === 'n8n-nodes-base.telegram').length} nodes)`);
}

// ── CHECK 6: Node count ──
const totalNodes = nodes.filter(n => n.type !== 'n8n-nodes-base.stickyNote').length;
if (totalNodes < 30) {
  warnings.push(`LOW NODE COUNT: ${totalNodes} nodes. HUNTER v2.0 should have 50+ active nodes.`);
}

// ── CHECK 7: Schedule trigger ──
const hasSchedule = nodes.some(n => n.type === 'n8n-nodes-base.scheduleTrigger');
if (!hasSchedule) {
  warnings.push('No Schedule Trigger found. MARKET WATCH should run at 6AM ET daily.');
} else {
  passed.push('✅ Schedule Trigger present');
}

// ── CHECK 8: Mandatory filing checks ──
const hasH4 = nodes.some(n => n.name.includes('H4'));
const hasH17 = nodes.some(n => n.name.includes('H17'));
const hasH22 = nodes.some(n => n.name.includes('H22'));
if (!hasH4 || !hasH17 || !hasH22) {
  warnings.push(`DRIFT FIX: Mandatory filing checks incomplete. H4=${hasH4}, H17=${hasH17}, H22=${hasH22}`);
} else {
  passed.push('✅ Mandatory filing checks (H4/H17/H22) present');
}

// ── SCORE ──
const score = issues.length === 0 ? (warnings.length === 0 ? 'COMPLIANT' : 'COMPLIANT_WITH_WARNINGS') : 'NON_COMPLIANT';

return [{ json: {
  workflow_name: workflow.name || 'Unknown',
  total_nodes: totalNodes,
  http_nodes: httpNodes.length,
  compliance_score: score,
  issues_count: issues.length,
  warnings_count: warnings.length,
  passed_count: passed.length,
  issues,
  warnings,
  passed,
  checked_at: new Date().toISOString(),
  protocol_version: 'METATRON v10.7 | IRONCLAD v2.0',
  workflow_json_summary: {
    node_types: [...new Set(nodes.map(n => n.type))],
    has_correlation: hasH37 && hasH38 && hasH39,
    has_kill_switch: hasKillSwitch,
    has_telegram: hasTelegram,
    has_schedule: hasSchedule
  }
}}];

