// Format the AI assessment for Telegram and logging
const structural = $('Structural Compliance Check').first().json;
const aiOutput = $input.all()[0].json.output || $input.all()[0].json.text || 'AI assessment unavailable';

const emoji = structural.compliance_score === 'COMPLIANT' ? '✅' : structural.compliance_score === 'COMPLIANT_WITH_WARNINGS' ? '⚠️' : '❌';

const telegramMsg = `🔱 <b>METATRON COMPLIANCE REPORT</b>\n\n` +
  `<b>Workflow:</b> ${structural.workflow_name}\n` +
  `<b>Score:</b> ${emoji} ${structural.compliance_score}\n` +
  `<b>Nodes:</b> ${structural.total_nodes} (${structural.http_nodes} HTTP)\n` +
  `<b>Issues:</b> ${structural.issues_count} | <b>Warnings:</b> ${structural.warnings_count} | <b>Passed:</b> ${structural.passed_count}\n\n` +
  `<b>AI Assessment:</b>\n${aiOutput.substring(0, 3500)}\n\n` +
  `🔱 METATRON v10.7 | ${new Date().toISOString()}`;

return [{ json: {
  telegram_message: telegramMsg,
  full_report: {
    structural: structural,
    ai_assessment: aiOutput,
    generated_at: new Date().toISOString()
  }
}}];
